mapper.select:
SELECT '총 발전량' AS title, CONCAT(ROUND(COALESCE(SUM(dr.value_actual), 0), 2), ' kWh') AS value FROM daily_report dr INNER JOIN inverter i ON dr.inverter_id = i.id INNER JOIN plant p ON i.plant_id = p.id WHERE p.member_id = #{memberId} AND dr.base_date = #{selectedDate}
UNION ALL
SELECT '예상 발전량' AS title, CONCAT(ROUND(COALESCE(SUM(dr.value_expected), 0), 2), ' kWh') AS value FROM daily_report dr INNER JOIN inverter i ON dr.inverter_id = i.id INNER JOIN plant p ON i.plant_id = p.id WHERE p.member_id = #{memberId} AND dr.base_date = #{selectedDate}
UNION ALL
SELECT '평균 효율' AS title, CONCAT(ROUND(COALESCE(AVG(pi.efficiency), 0), 2), ' %') AS value FROM plant_info pi INNER JOIN plant p ON pi.plant_id = p.id WHERE p.member_id = #{memberId}
UNION ALL
SELECT '인버터 수' AS title, CONCAT(COUNT(i.id), ' 대') AS value FROM inverter i INNER JOIN plant p ON i.plant_id = p.id WHERE p.member_id = #{memberId}
UNION ALL
SELECT '장애 건수' AS title, CONCAT(COUNT(al.id), ' 건') AS value FROM alert_log al INNER JOIN plant p ON al.plant_id = p.id WHERE p.member_id = #{memberId} AND DATE(al.occurred_at) = #{selectedDate}
